-- MySQL SaaS/Tech Database Initialization

-- Disable foreign key checks for clean tear down
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `mrr_snapshots`;
DROP TABLE IF EXISTS `churn_events`;
DROP TABLE IF EXISTS `ticket_comments`;
DROP TABLE IF EXISTS `support_tickets`;
DROP TABLE IF EXISTS `feature_usage`;
DROP TABLE IF EXISTS `features`;
DROP TABLE IF EXISTS `invoice_items`;
DROP TABLE IF EXISTS `invoices`;
DROP TABLE IF EXISTS `subscriptions`;
DROP TABLE IF EXISTS `contacts`;
DROP TABLE IF EXISTS `companies`;
DROP TABLE IF EXISTS `plans`;
SET FOREIGN_KEY_CHECKS = 1;

-- Create tables
CREATE TABLE `plans` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `name` VARCHAR(50) UNIQUE NOT NULL,
    `monthly_price` DECIMAL(10, 2) NOT NULL,
    `seat_limit` INT NOT NULL,
    `has_advanced_analytics` TINYINT(1) NOT NULL,
    `has_custom_integrations` TINYINT(1) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `companies` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `name` VARCHAR(100) UNIQUE NOT NULL,
    `industry` VARCHAR(50) NOT NULL,
    `employee_count` INT NOT NULL,
    `country` VARCHAR(50) NOT NULL,
    `arr` DECIMAL(15, 2) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `contacts` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `company_id` INT NOT NULL,
    `first_name` VARCHAR(100) NOT NULL,
    `last_name` VARCHAR(100) NOT NULL,
    `email` VARCHAR(150) UNIQUE NOT NULL,
    `role` VARCHAR(50) NOT NULL,
    `last_login_date` DATETIME DEFAULT NULL,
    FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `subscriptions` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `company_id` INT NOT NULL,
    `plan_id` INT NOT NULL,
    `start_date` DATE NOT NULL,
    `end_date` DATE DEFAULT NULL,
    `status` VARCHAR(20) NOT NULL, -- Active, Cancelled, Paused, Trial
    `billing_cycle` VARCHAR(20) NOT NULL, -- Monthly, Annual
    FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE RESTRICT,
    FOREIGN KEY (`plan_id`) REFERENCES `plans` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `invoices` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `subscription_id` INT NOT NULL,
    `company_id` INT NOT NULL,
    `amount` DECIMAL(10, 2) NOT NULL,
    `status` VARCHAR(20) NOT NULL, -- Paid, Unpaid, Overdue, Void
    `issue_date` DATE NOT NULL,
    `due_date` DATE NOT NULL,
    `payment_date` DATE DEFAULT NULL,
    FOREIGN KEY (`subscription_id`) REFERENCES `subscriptions` (`id`) ON DELETE CASCADE,
    FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `invoice_items` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `invoice_id` INT NOT NULL,
    `description` VARCHAR(255) NOT NULL,
    `amount` DECIMAL(10, 2) NOT NULL,
    FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `features` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `name` VARCHAR(100) UNIQUE NOT NULL,
    `code` VARCHAR(50) UNIQUE NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `feature_usage` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `company_id` INT NOT NULL,
    `feature_id` INT NOT NULL,
    `usage_count` INT NOT NULL,
    `usage_date` DATE NOT NULL,
    FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE,
    FOREIGN KEY (`feature_id`) REFERENCES `features` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `support_tickets` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `company_id` INT NOT NULL,
    `contact_id` INT NOT NULL,
    `title` VARCHAR(255) NOT NULL,
    `priority` VARCHAR(20) NOT NULL, -- Low, Medium, High, Critical
    `status` VARCHAR(20) NOT NULL, -- Open, In Progress, Resolved, Closed
    `category` VARCHAR(50) NOT NULL, -- Billing, Technical, Feature Request, Onboarding
    `created_at` DATETIME NOT NULL,
    `resolved_at` DATETIME DEFAULT NULL,
    FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE,
    FOREIGN KEY (`contact_id`) REFERENCES `contacts` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `ticket_comments` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `ticket_id` INT NOT NULL,
    `contact_id` INT DEFAULT NULL, -- NULL indicates support agent reply
    `comment_text` TEXT NOT NULL,
    `created_at` DATETIME NOT NULL,
    FOREIGN KEY (`ticket_id`) REFERENCES `support_tickets` (`id`) ON DELETE CASCADE,
    FOREIGN KEY (`contact_id`) REFERENCES `contacts` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `churn_events` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `company_id` INT NOT NULL,
    `churn_date` DATE NOT NULL,
    `reason` VARCHAR(100) NOT NULL, -- Price, Competitor, Feature Gap, Company Shutdown, Budget Cut
    FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE `mrr_snapshots` (
    `id` INT AUTO_INCREMENT PRIMARY KEY,
    `snapshot_month` DATE NOT NULL,
    `plan_id` INT NOT NULL,
    `mrr` DECIMAL(15, 2) NOT NULL,
    `active_subscriptions_count` INT NOT NULL,
    FOREIGN KEY (`plan_id`) REFERENCES `plans` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

